SELECT * FROM ledger_posting WHERE txn_id IN
#{txnId}
ORDER BY txn_id, id

SELECT lp.* FROM ledger_posting lp
INNER JOIN accounts a ON lp.account_id = a.id
WHERE lp.account_type = #{accountType}
AND a.is_active = 1
AND (
    a.owner_user_id = #{ownerUserId}
    OR (a.owner_family_id IS NOT NULL AND a.owner_family_id = #{ownerFamilyId})
)
ORDER BY lp.created_at DESC

SELECT lp.* FROM ledger_posting lp INNER JOIN ledger_txn lt ON lp.txn_id = lt.txn_id WHERE lp.account_id IN
#{accountId}
ORDER BY lt.requested_at ASC, lp.id ASC

mapper.update:
UPDATE ledger_posting
SET account_balance_after = CASE id

        WHEN #{item.id} THEN #{item.accountBalanceAfter}

END,
parent_account_balance_after = CASE id

        WHEN #{item.id} THEN #{item.parentAccountBalanceAfter}

END
WHERE id IN

    #{item.id}
